    def rotateTheBox(self, boxGrid: List[List[str]]) -> List[List[str]]:
        m = len(boxGrid)
        if m == 0:
            return []
        n = len(boxGrid[0])

        # Create the rotated matrix of size n x m
        rotated = [['.' for _ in range(m)] for _ in range(n)]

        for i in range(m):
            for j in range(n):
                new_row = j
                new_col = m - 1 - i
                rotated[new_row][new_col] = boxGrid[i][j]

        # Process each column in the rotated matrix to let stones fall
        for col in range(m):
            available = n - 1  # starting from the bottom row
            for r in range(n-1, -1, -1):
                current = rotated[r][col]
                if current == '*':
                    # Obstacle encountered, stones can't pass below this
                    available = r - 1
                elif current == '#':
                    # Move the stone to the available position
                    rotated[r][col] = '.'  # current position becomes empty
                    rotated[available][col] = '#'  # place stone at available spot
                    available -= 1  # move available up

        return rotated

